Event Grid1.Load
&AuditPlusKey.FromImage(auditplus_att) &AuditPlusKey.Tooltiptext = "Attribute"
&AuditRecordAttributeGuid = AuditRecordAttributeGuid &AuditRecordTableGuid = AuditRecordTableGuid
For Each Where AuditAttributeMetadataGuid = &AuditRecordAttributeGuid Where AuditTableMetadataGuid = &AuditRecordTableGuid
Do Case Case AuditTableAttributeIsKey AND AuditTableAttributeIsDescriptionAttribute &AuditPlusKey.FromImage(auditplus_key_description) &AuditPlusKey.Tooltiptext = "Key and description" Case AuditTableAttributeIsKey AND AuditTableAttributeIsForeignKey &AuditPlusKey.FromImage(auditplus_key_foreign) &AuditPlusKey.Tooltiptext = "Key and foreign key" Case AuditTableAttributeIsKey &AuditPlusKey.FromImage(auditplus_key) &AuditPlusKey.Tooltiptext = "Key" Case AuditTableAttributeIsForeignKey AND AuditTableAttributeIsDescriptionAttribute &AuditPlusKey.FromImage(auditplus_foreign_description) &AuditPlusKey.Tooltiptext = "Foreign key and description" Case AuditTableAttributeIsForeignKey &AuditPlusKey.FromImage(auditplus_foreign) &AuditPlusKey.Tooltiptext = "Foreign Key" Case AuditTableAttributeIsDescriptionAttribute &AuditPlusKey.FromImage(auditplus_description) &AuditPlusKey.Tooltiptext = "Description" EndCase EndFor
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
//this code should be inside the For Each used to load the grid
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
