Sub 'LoadGeneral'
For Each order AuditRecordId Where AuditRecordId = &AuditRecordId
&AuditRecordDate = AuditRecordDate &AuditRecordUser = AuditRecordUser &AuditRecordDatabaseUser = AuditRecordDatabaseUser &AuditRecordOperation = AuditRecordOperation &AuditRecordTransactionGuid = AuditRecordTransactionGuid &AuditRecordTransaction = AuditRecordTransaction &AuditRecordTableGuid = AuditRecordTableGuid &AuditRecordTable = AuditRecordTable // &AuditRecordTableName = AuditRecordTableName &AuditRecordTableParent = AuditRecordTableParent &AuditRecordParentId = AuditRecordParentId &AuditRecordParentDescription = AuditRecordParentDescription &AuditRecordHasLevelRecords = AuditRecordHasLevelRecords &AuditRecordTransactionDescriptionAttributeValue = AuditRecordTransactionDescriptionAttributeValue &AuditRecordModifiedAttributes = AuditRecordModifiedAttributes &AuditRecordModifiedAttributesGrid = AuditRecordModifiedAttributesGrid &AuditRecordKeyValue = AuditRecordKeyValue &AuditRecordSessionId = AuditRecordSessionId &AuditRecordExtraInformation = AuditRecordExtraInformation &AuditRecordAttributeGuid = AuditRecordAttributeGuid
if AuditRecordHasLevelRecords <> true GXUITabsPanel_Ttb.HideTab(3) Endif
Exit EndFor
EndSub
